mapper.select:
SELECT i.* from fc_income i left join
uc_customer c on i.customerId = c.id WHERE 1 = 1


    AND (
    i.`code` LIKE concat('%', #{query.name}, '%') OR
    c.`code` LIKE concat('%', #{query.name}, '%') OR
    c.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND i.`issueDate`  >=  #{query.startDate}


    AND i.`issueDate`  <=  #{query.endDate}


ORDER BY i.createdTime DESC
